SELECT COUNT(*) AS TOTAL FROM CARGO C JOIN SERVIDOR S ON S.PK_SIAPE = C.FK_SIAPE WHERE S.GENERO = 'FEMININO' AND C.SIGLA_CAMPUS = 'INH' AND ((LOWER(S.AREA_INGRESSO) LIKE LOWER('%quimica%') OR LOWER(S.AREA_INGRESSO) LIKE LOWER('%quimica%'))) AND (C.DATA_ENTRADA <= DATE('now') AND COALESCE(C.DATA_SAIDA, DATE('now')) >= (DATE('now', '-5 years'))) AND (LOWER(C.FUNCAO) LIKE LOWER('%diret%') OR LOWER(C.FUNCAO) LIKE LOWER('%direc%') OR LOWER(C.FUNCAO) LIKE LOWER('%direc%'))